    public function run(): void
    {
        Schema::disableForeignKeyConstraints();
        DB::table('doc_repository')->truncate();
        DB::table('folder_repository')->truncate();
        Schema::enableForeignKeyConstraints();

        foreach (array_chunk($this->folders, 200) as $chunk) {
            DB::table('folder_repository')->insert(array_map(fn (array $data) => [
                'id' => $data['id'],
                'name' => $data['name'],
                'url' => $data['url'],
                'id_parent' => $data['parent'],
                'created_at' => $data['created_at'],
                'updated_at' => $data['updated_at'],
            ], $chunk));
        }

        foreach (array_chunk($this->docs, 200) as $chunk) {
            DB::table('doc_repository')->insert(array_map(fn (array $data) => [
                'id' => $data['id'],
                'name' => $data['name'],
                'folder_id' => $data['folder'],
                'created_at' => $data['created_at'],
                'updated_at' => $data['updated_at'],
            ], $chunk));
        }
    }
